from fractions import Fraction

def continued_fraction_postprocess(peaks, max_period=10):
    fractions = []
    for peak in peaks:
        peak = peak.replace(' ', '')
        if '.' in peak:
            numerator, denominator = peak.split('.')
            fraction = Fraction(int(numerator), int(denominator))
        else:
            fraction = Fraction(int(peak), 1)
        fractions.append(fraction)
    for i in range(2, max_period):
        for fraction in fractions:
            if fraction == Fraction(1, i):
                return i
    return None

