from fractions import Fraction

def continued_fraction_postprocess(peaks, max_period=10):
    fractions = []
    for peak in peaks:
        peak_bits = list(map(int, peak))
        if peak_bits[0] == 0:
            t = peak_bits[2]
        else:
            t = peak_bits[2] - 1
        fraction = Fraction(t, 2**2)
        fractions.append(fraction)
    best_period = None
    best_error = float('inf')
    for i in range(2, max_period):
        for fraction in fractions:
            error = abs(fraction - Fraction(1, i))
            if error < best_error:
                best_error = error
                best_period = i
    return best_period

